// frontend/src/pages/JobsPage.js
import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import api from '../services/api';
import JobCard from '../components/jobs/JobCard';

const JobsPage = () => {
    const [jobs, setJobs] = useState([]);
    const [loading, setLoading] = useState(true);
    const [filters, setFilters] = useState({
        township: '',
        category: '',
        search: ''
    });

    useEffect(() => {
        loadJobs();
    }, [filters]);

    const loadJobs = async () => {
        setLoading(true);
        try {
            const params = new URLSearchParams();
            if (filters.township) params.append('township', filters.township);
            if (filters.category) params.append('category', filters.category);

            const response = await api.get(`/jobs?${params}`);
            if (response.data.success) {
                let filteredJobs = response.data.data;

                // Client-side search filter
                if (filters.search) {
                    filteredJobs = filteredJobs.filter(job => 
                        job.title.toLowerCase().includes(filters.search.toLowerCase()) ||
                        job.description.toLowerCase().includes(filters.search.toLowerCase())
                    );
                }

                setJobs(filteredJobs);
            }
        } catch (error) {
            console.error('Error loading jobs:', error);
        } finally {
            setLoading(false);
        }
    };

    const handleFilterChange = (e) => {
        setFilters({
            ...filters,
            [e.target.name]: e.target.value
        });
    };

    const townships = [
        'All', 'Soweto', 'Alexandra', 'Khayelitsha', 'Tembisa', 
        'Katlehong', 'Umlazi', 'Mdantsane', 'Mamelodi'
    ];

    const categories = [
        'All', 'Gardening', 'Cleaning', 'Building', 'Plumbing', 
        'Painting', 'Electrical', 'Delivery', 'Moving', 'Handyman'
    ];

    return (
        <div className="jobs-page">
            <div className="jobs-header">
                <h1>Find Work in Your Area</h1>
                <Link to="/jobs/post" className="btn-primary">
                    + Post a Job
                </Link>
            </div>

            {/* Filters */}
            <div className="filters-section">
                <div className="search-box">
                    <input
                        type="text"
                        name="search"
                        placeholder="Search jobs..."
                        value={filters.search}
                        onChange={handleFilterChange}
                    />
                </div>
                <div className="filter-controls">
                    <select name="township" value={filters.township} onChange={handleFilterChange}>
                        {townships.map(town => (
                            <option key={town} value={town === 'All' ? '' : town}>
                                {town}
                            </option>
                        ))}
                    </select>
                    <select name="category" value={filters.category} onChange={handleFilterChange}>
                        {categories.map(cat => (
                            <option key={cat} value={cat === 'All' ? '' : cat}>
                                {cat}
                            </option>
                        ))}
                    </select>
                </div>
            </div>

            {/* Jobs Grid */}
            {loading ? (
                <div className="loading-spinner">Loading jobs...</div>
            ) : jobs.length === 0 ? (
                <div className="no-jobs">
                    <h3>No jobs found</h3>
                    <p>Try adjusting your filters or check back later</p>
                </div>
            ) : (
                <div className="jobs-grid">
                    {jobs.map(job => (
                        <JobCard key={job.id} job={job} />
                    ))}
                </div>
            )}
        </div>
    );
};

export default JobsPage;
